CREATE TABLE `products` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `name` varchar(255) NOT NULL,
  `category_id` int(11) NOT NULL,
  `base_price` decimal(15,2) NOT NULL,
  `price` decimal(15,2) NOT NULL,
  `discount` double NOT NULL,
